import React, { useState, useEffect } from 'react';
import axios from 'axios';

function RoomList() {
  const [rooms, setRooms] = useState([]);

  useEffect(() => {
    axios.get('/api/rooms')
      .then(response => setRooms(response.data));
  }, []);

  return (
    <div>
      <h1>Room List</h1>
      <ul>
        {rooms.map(room => (
          <li key={room._id}>{room.name} - {room.capacity}</li>
        ))}
      </ul>
    </div>
  );
}

export default RoomList;
