from django.db import models
from .managers import MasterKeyManager, EncryptionManager, DecryptionManager

class TOTPDevice(models.Model):
    key = models.BinaryField()

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._original_key = self.key

    def save(self, *args, **kwargs):
        if self.key != self._original_key:
            self.key = MasterKeyManager.encrypt(self.key)
        super().save(*args, **kwargs)

    @property
    def key(self):
        if not hasattr(self, '_key'):
            self._key = DecryptionManager.decrypt_data(self._original_key)
        return self._key

    @key.setter
    def key(self, value):
        self._key = value
        self._original_key = value
